"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[93671],{75874(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>o,default:()=>l,frontMatter:()=>r,metadata:()=>n,toc:()=>h});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 2 and IAS 32/special-purpose-acquisition-companie-b7f4772d91","title":"Special Purpose Acquisition Companies (SPAC)\uFF1AAccounting for Warrants at Acquisition","description":"October 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 2 and IAS 32/Special Purpose Acquisition Companies (SPAC)\uFF1AAccounting for Warrants at Acquisition.md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 2 and IAS 32","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-2-and-ias-32-56a750466e/special-purpose-acquisition-companie-b7f4772d91","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-2-and-ias-32-56a750466e/special-purpose-acquisition-companie-b7f4772d91","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"special-purpose-acquisition-companie-b7f4772d91","title":"Special Purpose Acquisition Companies (SPAC)\uFF1AAccounting for Warrants at Acquisition","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-2-and-ias-32-56a750466e/special-purpose-acquisition-companie-b7f4772d91","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Multi-currency Groups of Insurance Contracts (IFRS 17 and IAS 21)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-and-ias-21-6f301e9ffb/multi-currency-groups-of-insurance-c-7eba702cb6"},"next":{"title":"Supply Chain Financing Arrangements\u2014Reverse Factoring","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-7-and-ias-7-23a3130c76/supply-chain-financing-arrangements--38094fceff"}}');var s=i(74848),a=i(28453);let r={id:"special-purpose-acquisition-companie-b7f4772d91",title:"Special Purpose Acquisition Companies (SPAC)\uFF1AAccounting for Warrants at Acquisition",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-2-and-ias-32-56a750466e/special-purpose-acquisition-companie-b7f4772d91",sidebar_position:1},o,c={},h=[];function d(e){let t={blockquote:"blockquote",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.p,{children:"October 2022"}),"\n",(0,s.jsx)(t.p,{children:"The Committee received a request about an entity\u2019s acquisition of a special purpose acquisition company (SPAC). The request asked how the entity accounts for warrants on acquiring the SPAC."}),"\n",(0,s.jsx)(t.p,{children:"In the fact pattern the Committee discussed:"}),"\n",(0,s.jsx)(t.p,{children:"a. the entity acquires a SPAC that has raised cash in an initial public offering (IPO), obtaining control of the SPAC. The purpose of the acquisition is for the entity to obtain the cash and the SPAC\u2019s listing on a stock exchange. The SPAC does not meet the definition of a business in IFRS 3 Business Combinations and, at the time of the acquisition, has no assets other than cash."}),"\n",(0,s.jsx)(t.p,{children:"b. before the acquisition, the SPAC\u2019s ordinary shares are held by its founder shareholders and public investors. The ordinary shares are determined to be equity instruments as defined in IAS 32 Financial Instruments: Presentation. In addition to ordinary shares, the SPAC had also issued warrants to both its founder shareholders and public investors (the SPAC warrants):\ni. founder warrants were issued at the SPAC\u2019s formation as consideration for services the founders provided.\nii. public warrants were issued to public investors with ordinary shares at the time of the IPO."}),"\n",(0,s.jsx)(t.p,{children:"c. the entity issues new ordinary shares and new warrants to the SPAC\u2019s founder shareholders and public investors in exchange for the SPAC\u2019s ordinary shares and the legal cancellation of the SPAC warrants. The SPAC becomes a wholly-owned subsidiary of the entity and the entity replaces the SPAC as the entity listed on the stock exchange."}),"\n",(0,s.jsx)(t.p,{children:"d. the SPAC\u2019s founder shareholders and public investors are not SPAC employees nor will they provide services to the entity after the acquisition."}),"\n",(0,s.jsx)(t.p,{children:"e. the fair value of the instruments the entity issues to acquire the SPAC exceeds the fair value of the SPAC\u2019s identifiable net assets."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Which IFRS Accounting Standard applies to the SPAC acquisition?"}),"\nParagraph 2(b) of IFRS 3 states that IFRS 3 does not apply to \u2018the acquisition of an asset or a group of assets that does not constitute a business\u2019. In such cases, that paragraph\nrequires the acquirer to \u2018identify and recognise the individual identifiable assets acquired \u2026 and liabilities assumed\u2019."]}),"\n",(0,s.jsx)(t.p,{children:"In the fact pattern discussed, the acquisition of the SPAC is the acquisition of an asset or a group of assets that does not constitute a business. Therefore, the entity identifies and\nrecognises the individual identifiable assets acquired and liabilities assumed as part of the acquisition."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"What are the individual identifiable assets acquired and liabilities assumed?"}),"\nIn the fact pattern discussed, the entity acquires the cash held by the SPAC. The entity also considers whether it assumes the SPAC warrants as part of the acquisition and, consequently, whether it assumes a liability if those warrants are classified as financial liabilities."]}),"\n",(0,s.jsx)(t.p,{children:"In assessing whether it assumes the SPAC warrants as part of the acquisition, the entity considers the specific facts and circumstances of the transaction, including the terms and\nconditions of all agreements associated with the acquisition. For example, the entity considers the legal structure of the transaction and the terms and conditions of the SPAC\nwarrants and the new warrants the entity issues."}),"\n",(0,s.jsx)(t.p,{children:"The entity might conclude that the facts and circumstances are such that it:"}),"\n",(0,s.jsx)(t.p,{children:"a. assumes the SPAC warrants as part of the acquisition\u2014in this case, the entity issues ordinary shares to acquire the SPAC and assumes the SPAC warrants as part of the\nacquisition. The entity then issues new warrants to replace the SPAC warrants it has assumed.\nb. does not assume the SPAC warrants as part of the acquisition\u2014in this case, the entity issues both ordinary shares and new warrants to acquire the SPAC and does not\nassume the SPAC warrants."}),"\n",(0,s.jsxs)(t.blockquote,{children:["\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Additional considerations applicable when an entity concludes that it assumes the SPAC warrants as part of the acquisition"})}),"\n",(0,s.jsx)(t.p,{children:"How does the entity account for SPAC warrants assumed as part of the acquisition?"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"In the fact pattern discussed, the SPAC\u2019s founder shareholders and public investors are not SPAC employees nor will they provide services to the entity after the acquisition. Instead, the SPAC's founder shareholders and public investors hold the SPAC warrants solely in their capacity as owners of the SPAC. Therefore, the entity applies IAS 32 to determine whether the SPAC warrants are financial liabilities or equity instruments."}),"\n",(0,s.jsx)(t.blockquote,{children:"\n"}),"\n",(0,s.jsx)(t.p,{children:"How does the entity account for the replacement of the SPAC warrants?"}),"\n",(0,s.jsx)(t.blockquote,{children:"\n"}),"\n",(0,s.jsx)(t.p,{children:"The entity applies IAS 32 and IFRS 9 Financial Instruments to account for the replacement of the SPAC warrants with new warrants."}),"\n",(0,s.jsx)(t.blockquote,{children:"\n"}),"\n",(0,s.jsx)(t.p,{children:"However, because the entity negotiated the replacement of the SPAC warrants as part of the SPAC acquisition, it determines whether it accounts for any of the new warrants it\nissues as part of that acquisition. No IFRS Accounting Standard specifically applies in making this determination. Therefore, the entity applies paragraphs 10\u201311 of IAS 8 Accounting Policies, Changes in Accounting Estimates and Errors in developing and applying an accounting policy that results in information that is relevant and reliable."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Does the entity also acquire a stock exchange listing service?"})}),"\n",(0,s.jsx)(t.p,{children:"In the fact pattern discussed, the SPAC\u2019s stock exchange listing does not meet the definition of an intangible asset because it is not \u2018identifiable\u2019 as described in paragraph 12 of IAS 38 Intangible Assets. Accordingly, the stock exchange listing is not an identifiable asset acquired. Nonetheless, the Committee observed that:"}),"\n",(0,s.jsx)(t.p,{children:"a. paragraph 2 of IFRS 2 states that \u2018an entity shall apply this IFRS in accounting for all share-based payment transactions, whether or not the entity can identify specifically some or all of the goods or services received \u2026 In the absence of specifically identifiable goods or services, other circumstances may indicate that goods or services have been (or will be) received, in which case this IFRS applies.\u2019"}),"\n",(0,s.jsx)(t.p,{children:"b. paragraph 13A of IFRS 2 states that \u2018\u2026 if the identifiable consideration received (if any) by the entity appears to be less than the fair value of the equity instruments granted or liability incurred, typically this situation indicates that other consideration (ie unidentifiable goods or services) has been (or will be) received by the entity. The entity shall measure the identifiable goods or services received in accordance with this IFRS. The entity shall measure the unidentifiable goods or services received (or to be received) as the difference between the fair value of the share-based payment and the fair value of any identifiable goods or services received (or to be received).\u2019"}),"\n",(0,s.jsx)(t.p,{children:"The fair value of the instruments the entity issues to acquire the SPAC exceeds the fair value of the identifiable net assets acquired. Therefore, the Committee concluded that, in\napplying paragraphs 2 and 13A of IFRS 2, the entity:"}),"\n",(0,s.jsx)(t.p,{children:"a. receives a stock exchange listing service for which it has issued equity instruments as part of a share-based payment transaction; and\nb. measures the stock exchange listing service received as the difference between the fair value of the instruments issued to acquire the SPAC and the fair value of the identifiable net assets acquired."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Which IFRS Accounting Standard applies to the instruments issued?"}),"\nDepending on the specific facts and circumstances of the transaction, the entity issues ordinary shares\u2014or ordinary shares and new warrants\u2014in exchange for acquiring cash,\nfor acquiring the stock exchange listing service and for assuming any liability related to the SPAC warrants. The Committee observed that:"]}),"\n",(0,s.jsx)(t.p,{children:"a. IAS 32 applies to all financial instruments, with some exceptions. These exceptions include \u2018financial instruments, contracts and obligations under share-based payment transactions to which IFRS 2 Share-based Payment applies \u2026\u2019 (paragraph 4 of IAS 32).\nb. IFRS 2 applies to \u2018share-based payment transactions in which an entity acquires or receives goods or services. Goods includes inventories, consumables, property, plant and equipment, intangible assets and other non-financial assets \u2026\u2019(paragraph 5 of IFRS 2)."}),"\n",(0,s.jsx)(t.p,{children:"Therefore, the Committee concluded that the entity applies:"}),"\n",(0,s.jsx)(t.p,{children:"a. IFRS 2 in accounting for instruments issued to acquire the stock exchange listing service; and\nb. IAS 32 in accounting for instruments issued to acquire cash and assume any liability related to the SPAC warrants\u2014these instruments were not issued to acquire goods or services and are not in the scope of IFRS 2."}),"\n",(0,s.jsxs)(t.blockquote,{children:["\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Additional considerations applicable if the entity concludes that it does not assume the SPAC warrants as part of the acquisition"})}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Which types of instrument were issued for the SPAC\u2019s net assets and which were issued for the service?"}),"\n",(0,s.jsx)(t.blockquote,{children:"\n"}),"\n",(0,s.jsx)(t.p,{children:"If the entity concludes that the facts and circumstances are such that it does not assume the SPAC warrants as part of the acquisition, the entity issues both ordinary shares and new warrants to acquire cash and a stock exchange listing service. In this case, the entity determines to what extent it issued each type of instrument to acquire (i) the cash, and (ii) the stock exchange listing service. No IFRS Accounting Standard specifically applies to this determination. Therefore, the entity applies paragraphs 10\u201311 of IAS 8 in developing and applying an accounting policy that results in information that is relevant and reliable."}),"\n",(0,s.jsx)(t.blockquote,{children:"\n"}),"\n",(0,s.jsx)(t.p,{children:"The Committee observed that:\na. an entity could allocate the shares and new warrants to the acquisition of cash and the stock exchange listing service on the basis of the relative fair values of the instruments issued (that is, in the same proportion as the fair value of each type of instrument to the total fair value of all issued instruments). For example, if 80% of the total fair value of the instruments issued comprises ordinary shares, the entity could conclude that 80% of the fair value of instruments issued to acquire cash also comprises ordinary shares."}),"\n",(0,s.jsx)(t.blockquote,{children:"\n"}),"\n",(0,s.jsx)(t.p,{children:"b. an entity could use other allocation methods if they meet the requirements in paragraphs 10\u201311 of IAS 8. However, an accounting policy that results in the entity allocating all the new warrants issued to the acquisition of the stock exchange listing service solely to avoid the new warrants being classified as financial liabilities applying IAS 32 would not meet these requirements."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Conclusion"}),"\nThe Committee concluded that the principles and requirements in IFRS Accounting Standards provide an adequate basis for an entity to determine how to account for warrants on acquiring a SPAC in the fact pattern the Committee discussed. Consequently, the Committee decided not to add a standard-setting project to the work plan."]})]})}function l(e={}){let{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},28453(e,t,i){i.d(t,{R:()=>r,x:()=>o});var n=i(96540);let s={},a=n.createContext(s);function r(e){let t=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);